public class Notification
{
    [Key] public int Id { get; set; }
    [Required] [StringLength(100)] public string EntityType { get; set; }
    [Required] [StringLength(50)] public string EntityId { get; set; }
    [Required] [StringLength(20)] public string Operation { get; set; }
    [Required] [StringLength(256)] public string Message { get; set; }
