}
public enum EntityOperation { CREATE, UPDATE, DELETE }
```

### NotificationService.cs (namespace ContosoUniversity.Services)
```csharp
public class NotificationService : IDisposable
{
    private static readonly ConcurrentQueue<Notification> _queue = new();
    private static readonly int _maxQueueLength = 500;

    public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
    {
        SendNotification(entityType, entityId, null, operation, userName);
    }

    public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
    {
        // Creates Notification, enqueues, enforces max length
        var notification = new Notification { ... };
        _queue.Enqueue(notification);
        while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
    }

    public Notification ReceiveNotification()
    {
        return _queue.TryDequeue(out var notification) ? notification : null;
    }

    public void MarkAsRead(int notificationId) { /* no-op */ }

    private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
    {
        var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
            ? $"{entityType} '{entityDisplayName}'"
            : $"{entityType} (ID: {entityId})";
        return operation switch
        {
            EntityOperation.CREATE => $"New {displayText} has been created",
            EntityOperation.UPDATE => $"{displayText} has been updated",
            EntityOperation.DELETE => $"{displayText} has been deleted",
            _ => $"{displayText} operation: {operation}"
        };
    }

    public void Dispose() { }
}
```

## Requirements
1. Create these test files:
   - `PaginatedListTests.cs` — test constructor, HasPreviousPage, HasNextPage, Create with various page sizes and positions
   - `ModelTests.cs` — test Person.FullName, ErrorViewModel.ShowRequestId, Notification properties, Student and Instructor instantiation
   - `NotificationServiceTests.cs` — test SendNotification (both overloads), ReceiveNotification (with/without items), message generation for all EntityOperation values, with/without display name, MarkAsRead, Dispose

2. Use MSTest with `[TestClass]`, `[TestMethod]`, `[DataRow]` for parameterized tests
3. Use Arrange-Act-Assert pattern
4. Name tests as `Method_Condition_ExpectedResult`
5. IMPORTANT: The NotificationService uses a static ConcurrentQueue, so tests share state. Drain the queue before each test by calling ReceiveNotification in a loop until null.
6. After creating the files, build with: `cd /tmp/sv-f392c6a8e58f4940a67dc53149514c9b && dotnet build ContosoUniversity.Tests/ContosoUniversity.Tests.csproj -v q`
7. Then run: `cd /tmp/sv-f392c6a8e58f4940a67dc53149514c9b && dotnet test ContosoUniversity.Tests/ContosoUniversity.Tests.csproj --no-build -v n`
8. Fix any compilation or test failures.

