using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public class PaginatedListTests
{
    [TestMethod]
    public void Constructor_WithItems_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var result = new PaginatedList<string>(items, 10, 1, 3);

        Assert.AreEqual(3, result.Count);
        CollectionAssert.AreEqual(items, result.ToList());
    }

    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 3, 5);

        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2)]
    [DataRow(10, 3, 4)]
    [DataRow(1, 1, 1)]
    [DataRow(0, 5, 0)]
    [DataRow(11, 5, 3)]
    public void Constructor_CalculatesTotalPages(int count, int pageSize, int expectedTotalPages)
    {
        var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void Constructor_WithEmptyItems_CreatesEmptyList()
    {
        var result = new PaginatedList<string>(new List<string>(), 0, 1, 10);

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    [DataRow(1, false)]
    [DataRow(2, true)]
    [DataRow(3, true)]
    public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
    {
        var result = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        Assert.AreEqual(expected, result.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 3, true)]
    [DataRow(2, 3, true)]
    [DataRow(3, 3, false)]
    [DataRow(1, 1, false)]
    public void HasNextPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
    {
        // totalPages = ceil(count/pageSize); use count = totalPages * pageSize for exact pages
        var result = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);

        Assert.AreEqual(expected, result.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 4, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(16, result[0]);
        Assert.AreEqual(20, result[4]);
    }

    [TestMethod]
    public void Create_PartialLastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(13, result[2]);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItemSource_ReturnsSingleItem()
    {
        var source = new[] { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void Create_PageSizeEqualToCount_ReturnsSinglePage()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSizeOfOne_PaginatesCorrectly()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 1);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(2, result[0]);
        Assert.AreEqual(3, result.TotalPages);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public class ModelTests
{
    // --- Person / FullName ---

    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
