    [TestMethod]
    public void Instructor_OfficeAssignment_DefaultsToNull()
    {
        var instructor = new Instructor();

        Assert.IsNull(instructor.OfficeAssignment);
    }

    // --- ErrorViewModel ---

    [TestMethod]
    [DataRow("abc-123", true)]
    [DataRow("1", true)]
    [DataRow("", false)]
