        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void Notification_ReadAt_DefaultsToNull()
    {
        var notification = new Notification();

        Assert.IsNull(notification.ReadAt);
    }

    // --- EntityOperation enum ---

    [TestMethod]
    public void EntityOperation_HasExpectedValues()
    {
        Assert.AreEqual(0, (int)EntityOperation.CREATE);
        Assert.AreEqual(1, (int)EntityOperation.UPDATE);
        Assert.AreEqual(2, (int)EntityOperation.DELETE);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain static queue to avoid cross-test contamination
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service.Dispose();
    }

    // --- SendNotification (3-param overload) ---

    [TestMethod]
    public void SendNotification_ThreeParam_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_ThreeParam_WithUserName_SetsCreatedBy()
    {
        _service.SendNotification("Course", "10", EntityOperation.UPDATE, "admin");

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_ThreeParam_WithoutUserName_SetsCreatedByToSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    // --- SendNotification (5-param overload) ---

    [TestMethod]
    public void SendNotification_FiveParam_WithDisplayName_SetsMessage()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_FiveParam_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "42", (string?)null, EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_FiveParam_WithUserName_SetsCreatedBy()
    {
        _service.SendNotification("Course", "5", "Math 101", EntityOperation.UPDATE, "teacher");

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("teacher", notification.CreatedBy);
    }

    // --- Message generation for each EntityOperation ---

    [TestMethod]
    public void SendNotification_Create_WithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student 'Alice' has been created", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_Update_WithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Alice", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Student 'Alice' has been updated", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_WithDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Alice", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Student 'Alice' has been deleted", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_Create_WithoutDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "5", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Course (ID: 5) has been created", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_Update_WithoutDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "5", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Course (ID: 5) has been updated", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_WithoutDisplayName_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "5", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Course (ID: 5) has been deleted", notification!.Message);
    }

    // --- Notification properties set correctly ---

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsFalse(notification!.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();
        Assert.IsTrue(notification!.CreatedAt >= before && notification.CreatedAt <= after);
    }

    // --- ReceiveNotification ---

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _service.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsItemsInFifoOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();
        var fourth = _service.ReceiveNotification();

        Assert.AreEqual("A", first!.EntityType);
        Assert.AreEqual("B", second!.EntityType);
        Assert.AreEqual("C", third!.EntityType);
        Assert.IsNull(fourth);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesItemFromQueue()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNull(second);
