using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Hosting;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private static SchoolContext CreateContext(string? dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private static CoursesController CreateController(SchoolContext context)
    {
        var mockEnv = new Mock<IWebHostEnvironment>();
        mockEnv.Setup(e => e.WebRootPath).Returns("wwwroot");
        mockEnv.Setup(e => e.ContentRootPath).Returns(".");
        var mockLogger = new Mock<ILogger<CoursesController>>();
        return new CoursesController(context, mockEnv.Object, mockLogger.Object);
    }

    private static Department SeedDepartment(SchoolContext context)
    {
        var dept = new Department { Name = "Engineering", Budget = 100000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();
        return dept;
    }

    #region Index

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        using var context = CreateContext();
        var dept = SeedDepartment(context);
        context.Courses.AddRange(
            new Course { CourseID = 1001, Title = "Calculus", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        context.SaveChanges();
        var controller = CreateController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_IncludesDepartment()
    {
        using var context = CreateContext();
        var dept = SeedDepartment(context);
        context.Courses.Add(new Course { CourseID = 1003, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID });
        context.SaveChanges();
        var controller = CreateController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
