        IQueryable<EnrollmentDateGroup> data = from student in db.Students
            group student by student.EnrollmentDate into dateGroup
            select new EnrollmentDateGroup() { EnrollmentDate = dateGroup.Key, StudentCount = dateGroup.Count() };
        return View(data.ToList());
    }
    public ActionResult Contact() { ViewBag.Message = "Your contact page."; return View(); }
    public ActionResult Error() => View();
    public new ActionResult Unauthorized() { ViewBag.Message = "You don't have permission..."; return View(); }
}
